(window.webpackJsonp=window.webpackJsonp||[]).push([[20],{371:function(v,_,t){"use strict";t.r(_);var n=t(4),r=Object(n.a)({},(function(){var v=this,_=v.$createElement,t=v._self._c||_;return t("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[t("h1",{attrs:{id:"космический-странник"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#космический-странник"}},[v._v("#")]),v._v(" Космический странник")]),v._v(" "),t("p",[v._v("Стрелка индикатора кислорода медленно опускалась к красной зоне, я стоял один, в своём новом скафандре на тонкой льдине — одинок во всей Вселенной. Один шаг в сторону или повышение силы давления, одно неловкое распределение усилия или не погашенная вовремя инерция — тогда я узнаю наверняка, что таят в себе эти ледяные воды.\nЭта планетарная система была не обыкновенно красива, не смотря на то, что местное светило уже давно погасло, к ней долетал свет от других звёзд. Часть из которых тоже уже была мертва. Ещё немного света давал фонарь, расположенный на верхушке моего шлема.\nВ сердце планеты неутомимым потоком бурлила жизнь, турбулентный поток магнитного вихря бил прямо из южного полюса, проходил через парящий рядом с планетой спутник и входил обратно — примерно по центру планеты, почему не в северный полюс?\nМагнитный поток, проходя через атмосферу спутника, создавал удивительно красочные световые всплески — именно их мы заметили, сначала на приборах своих панелей, а после в иллюминаторы. Увидев такую красоту, я просто не смог удержаться и потребовал спустить меня в капсуле быстрого перемещения. Никто не стал возражать капитану космического шаттла, разве кроме штатного искусственного разума - Авы, но разве это могло остановить меня?")]),v._v(" "),t("hr"),v._v(" "),t("p",[v._v("За свою беспечность порой приходится платить, так и случилось. Капсула не смогла балансировать в водах планеты и ушла к ядру, немного спустя разлетевшись пучком протонов и нейтронов в разные стороны.")]),v._v(" "),t("p",[v._v("Эта планета напомнила ему Эцелат — одну из планет его родной солнечной системы, которую они покинули так давно, отособившись от собственного биологического вида. Быть может какая-то грусть по прошлому и имела место быть...")]),v._v(" "),t("hr"),v._v(" "),t("p",[v._v("На дисплее скафандра замелькало уведомление — Ава запрашивает сеанс связи. Неужели, наш шаттл до меня достучался?\nВ ледяной мгле, окутанной бурлящими частичками воды и тонких льдинок зажёгся яркий свет голографического проектора, установленного на шлеме скафандра.")]),v._v(" "),t("p",[v._v("— Ты где? Вышли координаты где тебя забрать. В вопросительной гримасе застыло белоснежное лицо черноволосой девушки, с глубокими выразительными глазами. Никто не программировал эту внешность для Авы, она выбрала её сама.")]),v._v(" "),t("p",[v._v("Космический странник многозначительно молчал.")]),v._v(" "),t("p",[v._v("— Стой, это твой индикатор кислорода? Ты ведь умрёшь.")]),v._v(" "),t("p",[v._v("Капитан расплылся в многозначительной улыбке.")]),v._v(" "),t("p",[v._v("— Нет! Ты что задумал?")]),v._v(" "),t("p",[v._v("— Ава... —начал было капитан шаттла, но слегка шатнулся. Вверх взлетела вспышка света голографического проектора, описывая в ледяной мгле цветные узоры. — Зачем всё это? —Капитан начал уходить под воду.")]),v._v(" "),t("p",[v._v("Планета, в иллюминаторе рядом расположенной спасательной капсулы, в это время озарялась миллиардами цветов.")]),v._v(" "),t("hr"),v._v(" "),t("p",[v._v("Я уходил вглубль ледяной воды, но к моему удивлению, стрелка индикатора температуры ползла в верх. Я закрыл глаза, перед моим взором стоял последний взгляд Авы — он был настороженно испуганный. Ава — ведь машина, пускай и биомеханическая, неужели она научилась переживать?\nМои размышления прервала клешня. Большая клешня, упавшая в этот бездонный океан, и стремительно вытаскивающая меня в верх. Стрелка кислорода к этому моменту уже была на нуле. Последнее что я помню — женский голос, — Думал я отпущу тебя просто так?")]),v._v(" "),t("hr"),v._v(" "),t("p",[v._v("Я стою у панели своего межгалактического шаттла, мы летим в глубь пустого ледяного космоса. Кажется мы бороздили здесь уже более миллиарда световых лет, но нет этой Вселенной ни конца ни края...\nНапротив меня иллюминатор, я закрыл глаза и почувствовал ветер... Это Ава включила телепорт ветра с моей родной планеты, она единственная из всего экипажа знает как меня поддержать, когда мне грустно.")]),v._v(" "),t("hr"),v._v(" "),t("p",[v._v("Мы летим вперёд, где нас ни ждёт ничего и никто. За всё время нам не удалось встретить формы жизни равной нам, разве что следы таковой в нескольких звёздных система — но похоже такие как мы не рождены чтобы жить.\nВстречали как-то техно-цивилизации, состоящие из одних роботов, совершенно не похожих на нас. Даже Ава, со всей её умственной мощностью, не смогла наладить с ними контакт. Всё что-то возились со своими механизмами, не обращая на нас никакого внимания.")])])}),[],!1,null,null,null);_.default=r.exports}}]);